/**
 * localhost 代理配置
 * 开发模式下自动启用 devServer proxy，支持 localhost 直接访问
 * 通过 envs/.env.local 配置代理环境和 Cookie，支持 boe/pre/online 多环境切换
 */
import fs from 'fs';
import path from 'path';

import dotenv from 'dotenv';

// 不同环境对应的域名映射
const PROXY_DOMAIN_MAP: Record<
  string,
  {
    aily: string;
    space: string;
    accounts: string;
    miaoda: string;
    internalApi: string;
    larkCover: string;
    larkDriveStream: string;
  }
> = {
  BOE: {
    aily: 'https://aily.feishu-boe.cn',
    space: 'https://www.feishu-boe.cn',
    accounts: 'https://accounts.feishu-boe.cn',
    miaoda: 'https://miaoda.feishu-boe.cn',
    internalApi: 'https://internal-api-lark-api.feishu-boe.cn',
    larkCover: 'https://internal-api-space.feishu-boe.cn',
    larkDriveStream: 'https://internal-api-drive-stream.feishu-boe.cn',
  },
  PRE: {
    aily: 'https://aily.feishu-pre.cn',
    space: 'https://www.feishu-pre.cn',
    accounts: 'https://accounts.feishu-pre.cn',
    miaoda: 'https://miaoda.feishu-pre.cn',
    internalApi: 'https://internal-api-lark-api.feishu-pre.cn',
    larkCover: 'https://internal-api.feishu.cn',
    larkDriveStream: 'https://internal-api-drive-stream.feishu.cn',
  },
  ONLINE: {
    aily: 'https://aily.feishu.cn',
    space: 'https://www.feishu.cn',
    accounts: 'https://accounts.feishu.cn',
    miaoda: 'https://miaoda.feishu.cn',
    internalApi: 'https://internal-api-lark-api.feishu.cn',
    larkCover: 'https://internal-api.feishu.cn',
    larkDriveStream: 'https://internal-api-drive-stream.feishu.cn',
  },
};

function createProxyConfig(
  target: string,
  cookie: string,
  csrfToken: string,
  extraHeaders: Record<string, string> = {}
) {
  return {
    target,
    changeOrigin: true,
    ...(cookie || Object.keys(extraHeaders).length
      ? {
          headers: {
            ...(cookie ? { Cookie: cookie } : {}),
            ...(csrfToken ? { 'x-lgw-csrf-token': csrfToken } : {}),
            ...extraHeaders,
          },
        }
      : {}),
  };
}

export function getLocalDevProxy(configDir: string): Record<string, object> | undefined {
  const envLocalPath = path.resolve(configDir, 'envs/.env.local');
  const examplePath = path.resolve(configDir, 'envs/.env.local.example');

  // .env.local 不存在时从 .env.local.example 复制一份
  if (!fs.existsSync(envLocalPath) && fs.existsSync(examplePath)) {
    fs.copyFileSync(examplePath, envLocalPath);
    console.log('[LOCAL_DEV] 已从 .env.local.example 创建 envs/.env.local，请配置 COOKIE 后重启');
  }

  const { parsed: localEnv = {} } = dotenv.config({
    path: envLocalPath,
    override: false,
    processEnv: {},
  });

  const proxyEnv = localEnv.PROXY_ENV || 'BOE';
  const domains = PROXY_DOMAIN_MAP[proxyEnv] || PROXY_DOMAIN_MAP.BOE;
  const cookie = localEnv.COOKIE || '';
  const csrfToken = cookie.match(/lgw_csrf_token=([^;]+)/)?.[1] || '';

  // 后端泳道 header（可选）
  const extraHeaders: Record<string, string> = {};
  if (localEnv.X_TT_ENV) extraHeaders['x-tt-env'] = localEnv.X_TT_ENV;
  if (localEnv.X_TT_BRANCH) extraHeaders['x-tt-branch'] = localEnv.X_TT_BRANCH;
  if (localEnv.FORCE_WORKBENCH) extraHeaders['force-workbench'] = localEnv.FORCE_WORKBENCH;

  // 设置端口号（EdenX 原生读取 PORT 环境变量）
  if (localEnv.PORT) {
    process.env.PORT = localEnv.PORT;
  }

  if (cookie) {
    const swimLane = Object.keys(extraHeaders).length
      ? `, \x1b[33mswim-lane: ${JSON.stringify(extraHeaders)}\x1b[0m`
      : '';
    console.log(
      `[LOCAL_DEV] env=${proxyEnv}, port=${localEnv.PORT || 8080}, target=${domains.aily}, cookie=已配置${swimLane}`
    );
  }

  const proxy = (target: string) => createProxyConfig(target, cookie, csrfToken, extraHeaders);

  return {
    '/ai/api': proxy(domains.aily),
    '/aily/api': proxy(domains.aily),
    '/play/api': proxy(domains.aily),
    '/workbench/api': proxy(domains.aily),
    '/bridge_hub': proxy(domains.aily),
    '/anyclaw_bridge_hub': proxy(domains.aily),
    '/vnc': proxy(domains.aily),
    '/ae': proxy(domains.aily),
    '/anyclaw': proxy(domains.aily),
    '/invite': proxy(domains.aily),
    '/space/api/box/stream/download/all': proxy(domains.larkDriveStream),
    '/space/api/box/stream/download/v2/cover': proxy(domains.larkCover),
    '/space': proxy(domains.space),
    // 与 ai-play 当前契约对齐：localhost 下也让浏览器可见请求走 accounts.*，
    // 不再额外把 csrf 请求折到 internal-api-lark-api。
    '/accounts/csrf': proxy(domains.accounts),
    '/accounts': proxy(domains.accounts),
    '/af/api': proxy(domains.miaoda),
    '/anyclaw/api': proxy(domains.aily),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any;
}

