/**
 * AgentProfile —— AgentDetail「个性化」tab 的数据容器。
 *
 * 这里只负责 agent 上下文、profile 数据读取和 loading / empty 外壳；
 * 有文件后的编辑交互收口在 ProfileEditor。
 */
import { type ReactElement } from 'react';

import { defineMessages, useI18n } from '@apaas-ai/i18n';

import { StatusState } from '@/components/status-state';

import { ProfileEditor } from './profile-editor';
import { ProfileSkeleton } from './profile-skeleton';
import { useAgentProfile } from '../../hooks/use-agent-profile';
import { useAgentDetailContext } from '../agent-detail/agent-detail-context';
import { DetailTabStateSlot } from '../common/detail-tab-state-slot';

const PERSONA_EMPTY_TEST_ID = 'agent-profile-empty';

const messages = defineMessages({
  empty: { id: 'agent_profile.empty', defaultMessage: '暂无内容' },
});

export function AgentProfile(): ReactElement {
  const i18n = useI18n();
  const { agentDetail, onOpenAllFiles } = useAgentDetailContext();
  const { list, documents, loading, updateDocument } = useAgentProfile(agentDetail.agent_uid);

  // unsupported 或空数组都统一落到内容空态，不在组件里维护额外错误文案。
  const fileMetas = list?.unsupported ? [] : (list?.documents ?? []);

  if (loading) return <ProfileSkeleton />;

  if (fileMetas.length === 0) {
    return (
      <DetailTabStateSlot>
        <StatusState
          status="no-data"
          description={i18n.formatMessage(messages.empty)}
          testId={PERSONA_EMPTY_TEST_ID}
        />
      </DetailTabStateSlot>
    );
  }

  return (
    <ProfileEditor
      key={agentDetail.agent_uid}
      agentId={agentDetail.agent_uid}
      agentType={agentDetail.provider_type}
      providerType={agentDetail.provider_type}
      fileMetas={fileMetas}
      documents={documents}
      updateDocument={updateDocument}
      onOpenAllFiles={onOpenAllFiles}
    />
  );
}

export default AgentProfile;

