  const dirtyTabKeys = useMemo(
    () =>
      Object.entries(drafts)
        .filter(([, state]) => state.draft !== state.saved)
        .map(([tabKey]) => tabKey),
    [drafts]
  );
  const currentDraft = activeTabKey === ALL_TAB_KEY ? undefined : drafts[activeTabKey];
  const currentDirty = currentDraft ? currentDraft.draft !== currentDraft.saved : false;

  const activeEntry = useMemo(
    () => documentEntries.find((entry) => entry.key === activeTabKey) ?? documentEntries[0],
    [activeTabKey, documentEntries]
  );

  /** 编辑器只允许修改真实后端文件 tab；“全部”只是入口占位。 */
  const handleChangeCurrent = useCallback(
    (nextValue: string) => {
      if (activeTabKey === ALL_TAB_KEY) return;
      patchDraft(setDrafts, activeTabKey, (state) => ({ ...state, draft: nextValue }));
    },
    [activeTabKey]
  );

  /** 保存仅提交当前文件，其它 dirty 文件继续留在本地 draft。 */
  const handleSaveCurrent = useCallback(async () => {
    if (activeTabKey === ALL_TAB_KEY || !activeEntry) return;

    const state = drafts[activeEntry.key];
    if (!state || state.draft === state.saved) return;

    const contentToSave = state.draft;
    setDraftSaving(setDrafts, activeEntry.key, true);

    try {
      await updateDocument({
        documentType: activeEntry.key,
        content: contentToSave,
      });
      setDraftSaved(setDrafts, activeEntry.key, contentToSave);
      track(WorkbenchTrackKeys.AgentProfileSaveResult, {
        trackParams: {
          agent_id: agentId,
          agent_type: agentType ?? providerType,
          document_type: activeEntry.key,
          result: 'success',
        },
      });
      toast.success(i18n.formatMessage(messages.saveSuccess));
    } catch (err) {
      setDraftSaving(setDrafts, activeEntry.key, false);
      track(WorkbenchTrackKeys.AgentProfileSaveResult, {
        trackParams: {
          agent_id: agentId,
          agent_type: agentType ?? providerType,
          document_type: activeEntry.key,
          result: 'fail',
          error_code: err instanceof Error ? err.name : 'unknown',
        },
      });
      report(err, { feature: 'API_Error', silent: true });
      toast.error(i18n.formatMessage(messages.saveFailed));
    }
  }, [activeEntry, activeTabKey, agentId, agentType, drafts, i18n, providerType, updateDocument]);

  /** 取消只回滚当前文件，避免影响其它未保存 tab。 */
  const handleCancelCurrent = useCallback(() => {
    if (activeTabKey === ALL_TAB_KEY) return;
    track(WorkbenchTrackKeys.AgentProfileFileAction, {
      trackParams: {
        agent_id: agentId,
        agent_type: agentType ?? providerType,
        document_type: activeTabKey,
        action: 'cancel',
      },
    });
    resetDraft(setDrafts, activeTabKey);
  }, [activeTabKey, agentId, agentType, providerType]);

  const handleTabChange = useCallback(
    (tabKey: string) => {
      if (tabKey === ALL_TAB_KEY && onOpenAllFiles) {
        track(WorkbenchTrackKeys.AgentProfileFileAction, {
          trackParams: {
            agent_id: agentId,
            agent_type: agentType ?? providerType,
            action: 'open_all_files',
          },
        });
        onOpenAllFiles();
        return;
      }
      track(WorkbenchTrackKeys.AgentProfileFileAction, {
        trackParams: {
          agent_id: agentId,
          agent_type: agentType ?? providerType,
          document_type: tabKey,
          action: 'switch',
        },
      });
      setActiveTabKey(tabKey);
    },
    [agentId, agentType, onOpenAllFiles, providerType]
  );

  return (
    <>
      {/*
       * dirty gutter / save toolbar 仅看 currentDirty + activeTabKey ≠ ALL_TAB_KEY，**不依赖 activeDocument**：
       * buildDocumentEntries() 允许 entry.document 为 undefined（fallback-by-index / partial Get / mock filter）；
       * 该状态下 editor 仍可基于 meta.editable 进入 dirty，若再门禁 activeDocument 用户会卡在"能改不能存"。
       */}
      <ProfileEditorContent
        activeTabKey={activeTabKey}
        allTabKey={ALL_TAB_KEY}
        documentEntries={documentEntries}
        drafts={drafts}
        hasCurrentDirtyDocument={currentDirty}
        shouldAppendAllTab={shouldAppendAllTab}
        tabItems={tabItems}
        onChangeCurrent={handleChangeCurrent}
        onTabChange={handleTabChange}
      />

      {activeTabKey !== ALL_TAB_KEY && currentDirty ? (
        <ProfileSaveToolbar
          saving={currentDraft?.saving ?? false}
          onSave={handleSaveCurrent}
          onCancel={handleCancelCurrent}
        />
      ) : null}

      <ProfileCloseGuard dirtyTabKeys={dirtyTabKeys} onFocusTab={setActiveTabKey} />
    </>
  );
}

