  isFetchingNextPage: boolean;
  onLoadMore: () => Promise<void>;
  onSelectArtifact: (artifact: Artifact) => void;
  onSelectAction: (action: ArtifactMenuAction['id'], item: ArtifactListItem) => void;
  canDownloadArtifact: (artifact: Artifact) => boolean;
