              }}
              onSelectItem={(selectedItem) => {
                track(WorkbenchTrackKeys.AgentArtifactsAction, {
                  trackParams: {
                    agent_id: agentId,
                    agent_type: agentType,
                    action: 'open_artifact',
                    artifact_id: selectedItem.id,
                  },
                });
                onSelectArtifact(selectedItem.artifact);
              }}
              onSelectAction={(action, selectedItem) => {
                track(WorkbenchTrackKeys.AgentArtifactsAction, {
                  trackParams: {
                    agent_id: agentId,
                    agent_type: agentType,
                    action,
                    artifact_id: selectedItem.id,
                  },
                });
                onSelectAction(action, selectedItem);
              }}
            />
          );
        })}
        {isFetchingNextPage ? (
          <div className="flex items-center justify-center py-2">
