/* eslint-disable @infra/max-lines-per-function */
/* intl-check-disable-file — post-API hookup will be i18n'd properly */
import { useMemo, useState, type ReactElement } from 'react';

import { toast } from 'sonner';

import { MobileSearchView } from '@/components/mobile-search-view';
import { StatusState } from '@/components/status-state';
import {
  SKILL_SEARCH_PUSH_VIEW_KEY,
  useAgentDetailContext,
  type AbilitiesSubTabComponentProps,
} from '@/features/agents';
import {
  ManageCard,
  ManageCardSkeleton,
  ManageEmptyState,
  SkillRemoveConfirmDialog,
  SkillUploadModal,
  getSkillStoreAdapter,
  AgentSkillDetailDialogHost,
  searchAgentSkills,
  toAppliedSkillPayload,
  useAgentInstalledSkills,
  useSkillEditModal,
  useSkillStoreState,
  useToggleAgentSkill,
  useUninstallAgentSkill,
  type SkillEditableInfo,
  type SkillManagerCallbacks,
  type ManageCardProps,
  type SkillRemoveConfirmDialogProps,
  type StoreSkill,
} from '@/features/skills';
import { useIsMobile } from '@/hooks/use-is-mobile';
import { useMobilePushView } from '@/hooks/use-mobile-push-view';
import { useWorkbenchIdentity } from '@/hooks/use-workbench-identity';
import { track, WorkbenchTrackKeys } from '@/lib/tea-tracker';
import { isExternalAgent } from '@/utils/agent-provider';

export const SKILL_PANEL_EMPTY_TEST_ID = 'skill-panel-empty';
export const SKILL_PANEL_LOADING_TEST_ID = 'skill-panel-loading';
export const SKILL_PANEL_LIST_TEST_ID = 'skill-panel-list';
const SKILL_PANEL_CARD_GRID_CLASS =
  'grid grid-cols-[repeat(auto-fit,minmax(min(328px,100%),1fr))] gap-3 pb-6';

// 尚未支持的 menu action 占位提示（editInChat 已接入；其它都有真实实现）
const PENDING_ACTION_MESSAGES: Partial<Record<string, string>> = {};

export function SkillPanel({ keyword, readonly }: AbilitiesSubTabComponentProps): ReactElement {
  const { agentDetail, onApplySkill, onEditSkillInChat } = useAgentDetailContext();
  const agentId = agentDetail.agent_uid;
  const agentType = agentDetail.provider_type;
  // 本地 / 外接 agent（Claude Code / Codex / OpenClaw / Hermes）的 chat runtime 走
  // LocalAgentConversation，没有「应用技能到对话」入口（不传 onApplySkill），
  // 「使用」按钮即使点了也无事发生——直接藏掉。aily-team / aily-buddy 仍保留按钮。
  const hideUseButton = isExternalAgent(agentType);
  // readonly 态由 sub-tab 工厂按 provider 派生（external / aily-team 走只读）：
  //   - ManageCard 的三点下拉菜单直接隐藏（包内通过 readonly prop 把 menuItems 短路成 []）
  //   - toggle 视觉保留但 handler 守卫吞掉（与 mcp tab 同款 UX，banner 业务方决定不要）

  // mobile 全屏搜索：点 SubTabBar 🔍（AgentAbilities 层）open `?_view=skill_search`，
  // 本 panel 通过同一 push-view key 渲染 <MobileSearchView>，命令式 searchAgentSkills 拉结果。
  const isMobile = useIsMobile();
  const skillSearch = useMobilePushView(SKILL_SEARCH_PUSH_VIEW_KEY);
  const { userId } = useWorkbenchIdentity();

  const { skills, loading, error, refetch } = useAgentInstalledSkills(agentId, keyword);
  const toggleMutation = useToggleAgentSkill();
  const uninstallMutation = useUninstallAgentSkill();
  const { openEditModal, editModal } = useSkillEditModal({
    onSaved: () => {
      refetch().catch(() => undefined);
    },
  });

  const [activeSkill, setActiveSkill] = useState<StoreSkill | null>(null);
  const [removeTarget, setRemoveTarget] = useState<SkillRemoveConfirmDialogProps['target']>(null);

  const handleToggle: ManageCardProps['onToggle'] = (skill, enabled): void => {
    if (!skill.id) return;
    if (readonly) return; // readonly：toggle 静默吞掉（banner 已提示去 aily builder 改）
    track(WorkbenchTrackKeys.AgentSkillAction, {
      trackParams: {
        agent_id: agentId,
        agent_type: agentType,
        action: 'toggle_skill',
        skill_id: skill.id,
        enabled,
      },
    });
    toggleMutation.mutate({
      agentId,
      skillId: skill.id,
      status: enabled ? 'enable' : 'disable',
    });
  };

  const handleMenuAction: ManageCardProps['onMenuAction'] = (skill, action): void => {
    if (!skill.id) return;
    // readonly：所有 mutation 类 menu action 都禁掉；只放过纯读 action（detail 走卡片
    // 整体 onClick，不经过 menu）。download 也禁，对齐 mcp tab「只读不导出」语义
    if (readonly) return;
    track(WorkbenchTrackKeys.AgentSkillAction, {
      trackParams: { agent_id: agentId, agent_type: agentType, action, skill_id: skill.id },
    });
    if (action === 'remove') {
      setRemoveTarget(skill);
      return;
    }
    if (action === 'edit') {
      openEditModal({
        id: skill.id,
        label: skill.label || skill.name,
        description: skill.description,
        iconUrl: skill.iconUrl ?? '',
        tags: skill.tags ?? [],
      } satisfies SkillEditableInfo);
      return;
    }
    if (action === 'replace') {
      useSkillStoreState.getState().openUploadForReplace(skill.id);
      return;
    }
    if (action === 'download') {
      void getSkillStoreAdapter()
        .downloadSkill(skill.id, skill.label || skill.name)
        .catch(() => toast.error('下载失败'));
      return;
    }
    if (action === 'editInChat') {
      onEditSkillInChat?.(toAppliedSkillPayload(skill));
      return;
    }
    const pendingMsg = PENDING_ACTION_MESSAGES[action];
    if (pendingMsg) {
      toast.info(pendingMsg);
    }
  };

  const handleConfirmRemove: SkillRemoveConfirmDialogProps['onConfirm'] = (skill): void => {
    if (!skill.id) return;
    track(WorkbenchTrackKeys.AgentSkillAction, {
      trackParams: { agent_id: agentId, agent_type: agentType, action: 'confirm_remove', skill_id: skill.id },
    });
    uninstallMutation.mutate(
      { agentId, skillId: skill.id },
      {
        // 不管成功 / 失败都关 dialog；toast 由 hook 内部统一发
        onSettled: () => setRemoveTarget(null),
      }
    );
  };

  // ManageCard 的 callbacks：详情打开 / try-in-chat 在卡片层接线
  const callbacks = useMemo<SkillManagerCallbacks>(
    () => ({
      onOpenDetail: (skillId: string) => {
        const found = skills.find((s) => s.id === skillId);
        if (found) {
          track(WorkbenchTrackKeys.AgentSkillAction, {
            trackParams: {
              agent_id: agentId,
              agent_type: agentType,
              action: 'open_detail',
              skill_id: skillId,
            },
          });
          setActiveSkill(found);
        }
      },
      // 当前 skill tab 列出的就是「已安装到这个 agent 的技能」,onAddSkill 不会被触发
      onAddSkill: () => undefined,
      // 「在对话中使用技能」—— 走 page-layer 的 onApplySkill 插 chip
      onTrySkillInChat: (_type, skill) => {
        if (skill) {
          track(WorkbenchTrackKeys.AgentSkillAction, {
            trackParams: {
              agent_id: agentId,
              agent_type: agentType,
              action: 'try_in_chat',
              skill_id: skill.id,
            },
          });
          onApplySkill?.(toAppliedSkillPayload(skill));
        }
      },
      // ManageCard 内部走 share-kit `SkillSharePanel`,不依赖 callback;空兜底
      onShareSkill: () => undefined,
    }),
    [agentId, agentType, skills, onApplySkill]
  );

  // 单卡渲染抽出 —— PC 列表与 mobile 搜索结果共用同一套 ManageCard 装配（callbacks / handlers
  // 一致）。opts.highlightKeyword 仅 PC 列表传（高亮搜索词）；mobile 搜索结果由 MobileSearchView
  // 自管 keyword，不透出给 children，故不高亮。
  // opts.searchResult：搜索结果区为纯浏览展示——强制 readonly（短路三点菜单）+ hideUseButton
  // （隐藏「使用」按钮），点卡片仍走详情；正式的启停 / 移除 / 使用在主列表操作。
  const renderSkillCard = (
    skill: StoreSkill,
    opts?: { highlightKeyword?: string; searchResult?: boolean }
  ): ReactElement => (
    <ManageCard
      key={skill.id}
      skill={skill}
      callbacks={callbacks}
      searchKeyword={opts?.highlightKeyword}
      onToggle={handleToggle}
      onMenuAction={handleMenuAction}
      hideAgents
      stretchActions
      manageTab="added"
      readonly={opts?.searchResult ? true : readonly}
      hideUseButton={opts?.searchResult ? true : hideUseButton}
    />
  );

  // MobileSearchView 命令式 onSearch：壳自管 keyword/debounce/竞态，这里只「关键字 → 结果」。
  // 无需 memo（壳内部用 ref 取最新实现）。
  const handleSkillSearch = (kw: string): Promise<StoreSkill[]> => searchAgentSkills(agentId, kw, userId);

  if (loading) {
    return (
      <div className={SKILL_PANEL_CARD_GRID_CLASS} data-testid={SKILL_PANEL_LOADING_TEST_ID}>
        {Array.from({ length: 3 }, (_, i) => (
          <ManageCardSkeleton key={i} stretchActions />
        ))}
      </div>
    );
  }
  if (error) {
    return (
      <StatusState
        testId="skill-panel-error"
        status="error"
        onAction={() => {
          Promise.resolve(refetch()).catch(() => undefined);
        }}
      />
    );
  }
  if (skills.length === 0) {
    return (
      <div data-testid={SKILL_PANEL_EMPTY_TEST_ID}>
        <ManageEmptyState className="!min-h-[220px] !flex-none" description="该助手暂未安装技能" />
      </div>
    );
  }

  return (
    <>
      <div className={SKILL_PANEL_CARD_GRID_CLASS} data-testid={SKILL_PANEL_LIST_TEST_ID}>
        {skills.map((skill) => renderSkillCard(skill, { highlightKeyword: keyword }))}
      </div>
      {/* mobile 全屏搜索页：点 SubTabBar 🔍 open `?_view=skill_search` → 本壳渲染。
          结果复用 renderSkillCard（同 PC 列表卡片）；壳自管 keyword/debounce/历史/状态机。 */}
      {isMobile ? (
        <MobileSearchView<StoreSkill>
          active={skillSearch.isOpen}
          onClose={skillSearch.close}
          onSearch={handleSkillSearch}
          history={{ storageKey: `agent.${agentId}.skills` }}
        >
          {(results) => (
            <div className="flex flex-col gap-3 px-4 pb-6">
              {results.map((skill) => renderSkillCard(skill, { searchResult: true }))}
            </div>
          )}
        </MobileSearchView>
      ) : null}
      <AgentSkillDetailDialogHost
        open={!!activeSkill}
        agentId={agentId}
        skillId={activeSkill?.id ?? null}
        hideUse={hideUseButton}
        onOpenChange={(open) => {
          if (!open) setActiveSkill(null);
        }}
        onTrySkillInChat={(_type, skill) => {
          if (skill) {
            onApplySkill?.(toAppliedSkillPayload(skill));
          }
        }}
      />
      <SkillRemoveConfirmDialog
        target={removeTarget}
        removing={uninstallMutation.isPending}
        onClose={() => setRemoveTarget(null)}
        onConfirm={handleConfirmRemove}
      />
      {editModal}
      <SkillUploadModal />
    </>
  );
}

export default SkillPanel;

