/**
 * AgentAbilities —— AgentDetail「技能」tab 父组件，机械消费 sub-tab 注册表。
 *
 * 设计：
 *   - 注册表由 `buildAbilitiesSubTabs(providerType)` 工厂派生（可见性 + readonly + extras）
 *   - 本组件只负责：active key 切换、keyword state、SubTabBar/容器渲染
 *   - 子 tab Component **自洽**（自己 useAgentDetailContext 取 agentID）
 *   - **零业务判断**：readonly / 可见性 / 顶部 extras 全由 entry 字段承载
 *
 * 加新 sub-tab：types.ts 加 key、constants.ts 加 SUB_TAB_LABELS、sub-tabs.ts 加 entry + 可见性 case，
 * 写 sub-tab Component（接 `{ keyword, readonly }`），本文件零碰。
 */
import { useEffect, useMemo, useState, type ReactElement } from 'react';

import { defineMessages, useI18n } from '@apaas-ai/i18n';
import { Button } from '@apaas-base/design/ui/button';
import { Search } from 'lucide-react';

import { useIsMobile } from '@/hooks/use-is-mobile';
import { useMobilePushView } from '@/hooks/use-mobile-push-view';
import { useTenantRelateDomain } from '@/hooks/use-tenant-relate-domain';

import { SUB_TAB_LABELS } from './constants';
import { ReadonlyBanner } from './readonly-banner';
import { buildAbilitiesSubTabs, isAbilitiesReadOnly, type AbilitiesSubTabInjections } from './sub-tabs';
import { type AbilitiesSubTabKey } from './types';
import { getAilyBuilderUrl } from '../../utils/external-urls';
import { useAgentDetailContext } from '../agent-detail/agent-detail-context';
import { SubTabBar } from '../common/sub-tab-bar';

// useMobilePushView 必须每次渲染稳定调用（hooks 规则），但 active sub-tab 不一定声明
// mobileSearchViewKey（如 mcp）。无全屏搜索时用这个 noop key 占位（永不被 open）。
const ABILITIES_SEARCH_NOOP_KEY = '__abilities_search_noop__';

export interface AgentAbilitiesProps {
  /**
   * Skill sub-tab 的 page-level 注入。**可选**：caller 不传时 skill 子 tab 整个
   * 不渲染（features/agents 不直接依赖 features/skills，由 page 层装配 SkillPanel
   * + AddSkillButton 后传入；不需要 skill 视图的场景如 storybook / hook 默认值路径
   * 留空即可）。
   */
  injections?: AbilitiesSubTabInjections;
}

const AGENT_ABILITIES_CONTAINER_CLASS = 'flex w-full flex-col gap-3 pt-6';
const AGENT_ABILITIES_TAB_STRIP_CLASS = 'shrink-0 pl-4 pr-4';
const AGENT_ABILITIES_CONTENT_CLASS = 'min-h-0 flex-1 px-3';

const messages = defineMessages({
  // 子 tab 公用搜索 input 文案（skill / mcp 共享，未来加新搜索 tab 也用同一组）
  searchPlaceholder: {
    id: 'Spring_AiWeb_NexusMCPMgt_Search_Placeholder',
    defaultMessage: '搜索',
  },
  searchClose: {
    id: 'agents.abilities.search_close',
    defaultMessage: '关闭搜索',
  },
});

export function AgentAbilities({ injections }: AgentAbilitiesProps): ReactElement {
  const i18n = useI18n();
  const { agentDetail } = useAgentDetailContext();
  const { domain: tenantDomain } = useTenantRelateDomain();
  // 团队助手 / 外接智能体只读：整组 sub-tab 顶部统一展示「去自定义开发界面修改」提示（缺陷 7331447010）
  const readonly = isAbilitiesReadOnly(agentDetail.provider_type);
  const builderUrl = readonly ? getAilyBuilderUrl(tenantDomain, agentDetail.agent_uid) : undefined;
  const subTabs = useMemo(
    () => buildAbilitiesSubTabs(agentDetail.provider_type, injections),
    [agentDetail.provider_type, injections]
  );
  // subTabs 可能为空（外接 agent + 没传 skill injection）；用 undefined 占位
  // 等待用户 override，渲染空容器，不抛 `subTabs[0]!.key` 异常
  const [activeKey, setActiveKey] = useState<AbilitiesSubTabKey | undefined>(() => subTabs[0]?.key);
  const [keyword, setKeyword] = useState('');

  // 切 sub-tab 时清空搜索 keyword，避免跨 tab 误生效
  useEffect(() => {
    setKeyword('');
  }, [activeKey]);

  // provider 切换或 injections 变更导致 sub-tabs 集合变化时，activeKey 若已不在新集合
  // fallback 到首项（首项可能仍是 undefined）
  useEffect(() => {
    if (activeKey === undefined || !subTabs.some((t) => t.key === activeKey)) {
      setActiveKey(subTabs[0]?.key);
    }
  }, [subTabs, activeKey]);

  const tabItems = useMemo(
    () =>
      subTabs.map((entry) => ({
        key: entry.key,
        label: i18n.formatMessage(SUB_TAB_LABELS[entry.key]),
        testId: `abilities-tab-${entry.key}`,
      })),
    [i18n, subTabs]
  );

  // mobile + active sub-tab 声明了 mobileSearchViewKey（如 skill）→ 搜索走全屏 push view：
  // SubTabBar 不渲染 inline search，改在 extraRightSlot 放 🔍，点击 open 该 push view，
  // 由 sub-tab component（SkillPanel）自渲染 <MobileSearchView> 接同一 key。零业务判断——
  // AgentAbilities 只机械消费 entry.mobileSearchViewKey，不感知具体是 skill 还是别的。
  // hooks 必须在 early return 前稳定调用：activeEntry 在此提前算（subTabs 空时 undefined）。
  const isMobile = useIsMobile();
  const activeEntry = subTabs.find((t) => t.key === activeKey) ?? subTabs[0];
  const mobileSearchViewKey = isMobile ? activeEntry?.mobileSearchViewKey : undefined;
  const fullScreenSearch = useMobilePushView(mobileSearchViewKey ?? ABILITIES_SEARCH_NOOP_KEY);
  const useFullScreenSearch = Boolean(mobileSearchViewKey);

  if (subTabs.length === 0) {
    // 无可渲染 sub-tab（caller 没传 skill injection，且当前 provider visible
    // 列表里只有 skill）—— 渲染空容器占位，不抛错
    return <div className={AGENT_ABILITIES_CONTAINER_CLASS} data-testid="agent-abilities" />;
  }

  const active = activeEntry ?? subTabs[0]!;
  const ActiveComponent = active.component;
  const ExtrasComponent = active.subTabBarExtras;
  const searchPlaceholder = i18n.formatMessage(messages.searchPlaceholder);

  return (
    <div className={AGENT_ABILITIES_CONTAINER_CLASS} data-testid="agent-abilities">
      {readonly ? (
        <div className="px-4">
          <ReadonlyBanner builderUrl={builderUrl} />
        </div>
      ) : null}
      <div className={AGENT_ABILITIES_TAB_STRIP_CLASS} data-testid="agent-abilities-tab-strip">
        <SubTabBar<AbilitiesSubTabKey>
          items={tabItems}
          value={active.key}
          onValueChange={setActiveKey}
          // mobile 全屏搜索时不挂 inline search（🔍 移到 extraRightSlot 触发 push view）
          search={
            useFullScreenSearch
              ? undefined
              : {
                  keyword,
                  onKeywordChange: setKeyword,
                  placeholder: searchPlaceholder,
                  closeAriaLabel: i18n.formatMessage(messages.searchClose),
                }
          }
          extraRightSlot={
            <>
              {useFullScreenSearch ? (
                <Button
                  type="button"
                  variant="ghost"
                  size="icon-sm"
                  aria-label={searchPlaceholder}
                  onClick={() => fullScreenSearch.open()}
                  data-testid="agent-abilities-mobile-search-trigger"
                >
                  <Search aria-hidden className="size-4" />
                </Button>
              ) : null}
              {ExtrasComponent ? <ExtrasComponent /> : null}
            </>
          }
        />
      </div>
      <div className={AGENT_ABILITIES_CONTENT_CLASS} data-testid="agent-abilities-content">
        <ActiveComponent keyword={keyword} readonly={active.readonly} />
      </div>
    </div>
  );
}

export default AgentAbilities;

