describe('PermissionRow', () => {
  const isSwitchDisabled = (element: HTMLElement): boolean =>
    element.hasAttribute('disabled') ||
    element.getAttribute('aria-disabled') === 'true' ||
    element.hasAttribute('data-disabled');

  it('required 权限保持禁用并展示 tooltip 文案', () => {
    const { getByTestId, getByText } = render(
      <PermissionRow
        item={{
          id: 'permission-required',
          name: '查看通讯录消息',
          permissionKey: 'im:chat:read',
          identityType: '应用身份',
          enabled: true,
          required: true,
        }}
        onToggle={() => undefined}
      />
    );

    expect(isSwitchDisabled(getByTestId('permission-switch-permission-required'))).toBe(true);
    expect(getByText('为确保智能伙伴正常运行，该权限不支持关闭')).toBeTruthy();
  });

  it('切换权限时在异步完成前保持禁用，结束后恢复可用', async () => {
    let resolveToggle: (() => void) | null = null;
    const onToggle = vi.fn(
      () =>
        new Promise<void>((resolve) => {
          resolveToggle = resolve;
        })
    );

    const { getByTestId } = render(
      <PermissionRow
        item={{
          id: 'permission-1',
          name: '更新群信息',
          permissionKey: 'im:chat:write',
          identityType: '用户身份',
          enabled: false,
          required: false,
        }}
        onToggle={onToggle}
      />
    );

    const toggleSwitch = getByTestId('permission-switch-permission-1');
    expect(isSwitchDisabled(toggleSwitch)).toBe(false);

    fireEvent.click(toggleSwitch);

    expect(onToggle).toHaveBeenCalledTimes(1);
    expect(onToggle).toHaveBeenCalledWith(true);
    expect(isSwitchDisabled(toggleSwitch)).toBe(true);

    resolveToggle?.();
    await waitFor(() => {
      expect(isSwitchDisabled(toggleSwitch)).toBe(false);
    });
  });

  it('移动端标题和权限 key 都允许最多两行展示', () => {
    const { container } = render(
      <PermissionRow
        item={{
          id: 'permission-mobile',
          name: '这是一个很长很长的权限名称需要在移动端展示为最多两行文本',
          permissionKey: 'im:chat:read:very:long:permission:key:used:for:mobile:display',
          identityType: '用户身份',
          enabled: true,
          required: false,
        }}
        onToggle={() => undefined}
      />
    );

    const textNodes = container.querySelectorAll('[data-line-clamp]');
    expect(textNodes[0]?.getAttribute('data-line-clamp')).toBe('2');
    expect(container.querySelector('.float-left')).toBeTruthy();
    expect(container.querySelector('.max-h-\\[44px\\]')).toBeTruthy();
    expect(container.querySelectorAll('wbr').length).toBeGreaterThan(0);
  });

  it('移动端搜索结果和普通列表保持一致的两行换行规则', () => {
    const { container } = render(
      <PermissionRow
        item={{
          id: 'permission-search',
          name: '查看通讯录消息',
          permissionKey: 'application:bot.menu:readonly:very:long:key',
          identityType: '用户身份',
          enabled: true,
          required: false,
        }}
        variant="mobile-search"
        highlightKeyword="bot"
        onToggle={() => undefined}
      />
    );

    expect(container.querySelector('.px-4')).toBeTruthy();
    expect(container.querySelector('.float-left')).toBeTruthy();
    expect(container.querySelector('.max-h-\\[44px\\]')).toBeTruthy();
    expect(container.querySelectorAll('wbr').length).toBeGreaterThan(0);
    expect(container.querySelector('.text-info')).toBeTruthy();
    const textNodes = container.querySelectorAll('[data-line-clamp]');
    expect(textNodes[0]?.getAttribute('data-line-clamp')).toBe('2');
  });
});

