import type { PermissionItem } from '../types';

interface PermissionRowProps {
  item: PermissionItem;
  onToggle: (enabled: boolean) => void | Promise<void>;
  variant?: 'default' | 'mobile-search';
  highlightKeyword?: string;
}

function escapeRegExp(s: string): string {
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function renderMobilePermissionKey(permissionKey: string): JSX.Element {
  return (
    <>
      {permissionKey.split(/([:./])/).map((segment, index) => (
        <Fragment key={`${segment}-${index}`}>
          {segment}
          {[':', '.', '/'].includes(segment) ? <wbr /> : null}
        </Fragment>
      ))}
    </>
  );
}

function renderHighlightedText(text: string, keyword: string): ReactNode {
  return keyword ? <HighlightKeyword keyword={keyword}>{text}</HighlightKeyword> : text;
}

function pushPermissionKeyNodes(
  nodes: ReactNode[],
  text: string,
  keyPrefix: string,
  highlighted = false
): void {
  const textClassName = highlighted ? 'font-medium text-info' : undefined;
  text.split(/([:./])/).forEach((segment, index) => {
    const nodeKey = `${keyPrefix}-${index}`;
    if ([':', '.', '/'].includes(segment)) {
      nodes.push(
        textClassName ? (
          <span key={nodeKey} className={textClassName}>
            {segment}
          </span>
        ) : (
          <Fragment key={nodeKey}>{segment}</Fragment>
        )
      );
      nodes.push(<wbr key={`${nodeKey}-wbr`} />);
      return;
    }

    nodes.push(
      textClassName ? (
        <span key={nodeKey} className={textClassName}>
          {segment}
        </span>
      ) : (
        <Fragment key={nodeKey}>{segment}</Fragment>
      )
    );
  });
}

function renderHighlightedMobilePermissionKey(permissionKey: string, keyword: string): JSX.Element {
  if (!keyword) {
    return renderMobilePermissionKey(permissionKey);
  }

  const regex = new RegExp(`(${escapeRegExp(keyword)})`, 'gi');
