    if (!result) {
      break;
    }

    const start = result.index;
    const end = result.index + result[0].length;
    pushPermissionKeyNodes(nodes, permissionKey.slice(cursor, start), `plain-${index}`);
    pushPermissionKeyNodes(nodes, permissionKey.slice(start, end), `highlight-${index}`, true);
    cursor = end;
    index += 1;
  }

  pushPermissionKeyNodes(nodes, permissionKey.slice(cursor), `plain-${index}`);
  return <>{nodes}</>;
}

