/**
 * AgentDetailInfo —— panel 中段信息区（头像 / 名 / 简介 / provider 信息 / stats）。
 *
 * narrow / wide 自适应：panel 按容器宽（断点 500px）算 isWide 传入，本组件据此切 `data-wide`，
 * 子元素用 `group-data-[wide=true]/info:*` modifier 切布局。跨断点翻转由 panel 包进 View Transition：
 * 头像 / 右列各挂 `[view-transition-name:*]`，VT 拍旧/新位图做 crossfade+morph，平滑 column↔row 重排 +
 * 内容显隐（纯 CSS / framer layout 都做不到重排 morph）。无 VT 支持时退化为瞬切。
 *
 * 视觉布局：
 *   narrow（panel < 500px, Figma 322:25055）：
 *     ┌───────────┐
 *     │  Avatar   │ 96
 *     ├───────────┤  mt-3 (12)
 *     │   Name    │ 20/28/w400
 *     ├───────────┤  mt-2.5 (10)
 *     │  intro    │ 12/16/w400
 *     ├───────────┤  mt-7 (28, 视觉分组)
 *     │   stats   │ 数字 24/36/w700 + label 下方 12/16
 *     └───────────┘
 *
 *   wide（panel ≥ 500px, Figma 322:27683）：
 *     ┌────────┬─────────────────────┐
 *     │ Avatar │ Name 20/28/w400     │
 *     │   80   │ intro 12/20/w400    │ gap-1 (4)
 *     │        │ stats 内联 12/20    │ stat num w500 / label w400
 *     └────────┴─────────────────────┘
 *   外层 flex-row gap-24，stat 内 row gap-1
 *
 * Provider 信息（来源 / 运行电脑）仅 ExternalAgent 显示，作为内嵌段落。
 *
 * stats 缺失（接口未对接）：3 项数字均显示 "-" 占位，label 正常渲染。
 */
import { useState, type ReactElement, type ReactNode } from 'react';

import { defineMessage, FormattedMessage, useI18n } from '@apaas-ai/i18n';
import { cn } from '@apaas-base/design/lib/utils';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@apaas-base/design/ui/tooltip';
import EditOutlined from '@universe-design/icons-react/EditOutlined';

import { type AgenthubModule } from '@/apis/types';
import { AgentAvatar } from '@/components/agent-avatar';
import { Text } from '@/components/text/text';
import { useAgentHealth } from '@/hooks/use-agent-health';
import { isExternalAgent, providerLabel } from '@/utils/agent-provider';

import { EditInfoDialog } from './edit-info-dialog';
import { formatStatCount, formatStatValue, messages, STATS_PLACEHOLDER } from '../../utils/agent-detail-info';

// 名称 hover 显示的编辑 icon tooltip（向下）
const editTooltipMsg = defineMessage({
  id: 'agents.detail_info.edit_tooltip',
  defaultMessage: '编辑基本信息',
});

export interface AgentDetailInfoProps {
  detail: AgenthubModule.Agent._Agent.AgentDetail;
  /** 传入后头像 hover 显示半透明 + Camera 遮罩，点击触发；省略不渲染编辑态 */
  onEditAvatar?: () => void;
  /**
   * 名称 / 描述编辑保存回调（EditInfoDialog 收集后回调）；与 onEditAvatar 对称，由 panel 注入其
   * 内聚的 handleUpdate（乐观写 cache + mutation 持久化 + 通知 host）。省略时 dialog 保存为 no-op。
   */
  onEditInfo?: (patch: { name: string; description: string }) => void;
  /**
   * narrow / wide 由 panel 按容器宽度（断点 500px）判定后传入；本组件据此切 data-wide 布局类。
   * 缺省 false（narrow）；mobile 版忽略本 prop。
   */
  isWide?: boolean;
  className?: string;
}

export function AgentDetailInfo({
  detail,
  onEditAvatar,
  onEditInfo,
  isWide = false,
  className,
}: AgentDetailInfoProps): ReactElement {
  const i18n = useI18n();

  // 头像 dot 走 live 健康（useAgentHealth 批量轮询）；首屏用 detail 快照兜底，避免 dot 闪空。
  // dot 颜色派生在 AgentAvatar 内（utils/agent-dot 三规则），无需 provider 特判。
  const health = useAgentHealth(detail.agent_uid, {
    fallback: {
      status: detail.status,
      connectivity: detail.connectivity,
      connect_err_msg: detail.connect_err_msg,
    },
  });
  const name = detail.name ?? detail.agent_uid;
  const description = detail.description ?? '';
  const [editOpen, setEditOpen] = useState(false);

  // Panel 顶部三指标走 user_stat（当前用户 × agent 关系维度），跟 agent 全局 stat 区分
  const { user_stat: userStat } = detail;

  // wide 富文本：ICU 模板内 <num> 标签包裹数字，render fn 注入 n900 / medium 样式；
  // 其余 "天 陪伴" 部分继承 dt 的 n500 / normal（Figma 322:27683）。
  // <FormattedMessage> 的 id / defaultMessage 必须是字符串字面量（lint 规则
  // @infra/i18n-message-descriptor + babel 静态提取），不能 spread。所以 3 段 ICU
  // 模板直接 inline 写在下面 statItems 里。
  // FormattedMessage 把 <num> 渲染结果与外围纯文本一起返回成数组——给 chunk span 一个稳定 key，
  // 避免 react "list child needs unique key" 警告
  const numChunk = (chunks: ReactNode) => (
    <span key="num" className="font-medium text-n900">
      {chunks}
    </span>
  );
  // value 缺失时 wide 退回 "- 陪伴天数"（用 narrow label 兜底；wide 单位无数字读起来不连贯）
  const widePlaceholder = (narrowMessage: typeof messages.companionDaysNarrow) =>
    `${STATS_PLACEHOLDER} ${i18n.formatMessage(narrowMessage)}`;

  const statItems: Array<{
    value: ReactNode;
    narrowLabel: string;
    wideLabel: ReactNode;
  }> = [
    {
      value: formatStatValue(userStat?.companion_days, i18n),
      narrowLabel: i18n.formatMessage(messages.companionDaysNarrow),
      wideLabel:
        typeof userStat?.companion_days === 'number' ? (
          <FormattedMessage
            id="agents.detail_info.companion_days_label_wide"
            defaultMessage="<num>{number}</num> 天 陪伴"
            values={{ number: formatStatCount(userStat.companion_days, i18n), num: numChunk }}
          />
        ) : (
          widePlaceholder(messages.companionDaysNarrow)
        ),
    },
    {
      value: formatStatValue(userStat?.conversation_count, i18n),
      narrowLabel: i18n.formatMessage(messages.interactionCountNarrow),
      wideLabel:
        typeof userStat?.conversation_count === 'number' ? (
          <FormattedMessage
            id="agents.detail_info.interaction_count_label_wide"
            defaultMessage="<num>{number}</num> 条 对话"
            values={{ number: formatStatCount(userStat.conversation_count, i18n), num: numChunk }}
          />
        ) : (
          widePlaceholder(messages.interactionCountNarrow)
        ),
    },
    {
      value: formatStatValue(userStat?.task_count, i18n),
      narrowLabel: i18n.formatMessage(messages.taskCountNarrow),
      wideLabel:
        typeof userStat?.task_count === 'number' ? (
          <FormattedMessage
            id="agents.detail_info.task_count_label_wide"
            defaultMessage="<num>{number}</num> 个 任务"
            values={{ number: formatStatCount(userStat.task_count, i18n), num: numChunk }}
          />
        ) : (
          widePlaceholder(messages.taskCountNarrow)
        ),
    },
  ];

  return (
    <section
      // group/info + data-wide：narrow/wide 由 panel 按宽度传入的 isWide 驱动（替代 @container CQ）；
      // 命名 group/info 避免撞 AgentAvatar 内未命名 group-hover（相机蒙版）。子元素用 group-data-[wide=true]/info:*
      data-wide={isWide ? 'true' : 'false'}
      className={cn(
        'group/info',
        // narrow: Figma 322:25055 padding 24/16/32/16，垂直堆叠居中
        'flex w-full flex-col items-center px-4 pt-6 pb-8',
        // wide: Figma 322:27683 padding 24/24/32/24，flex-row gap-6 (24)（section 自身用 data-[wide]）
        'data-[wide=true]:flex-row data-[wide=true]:items-start data-[wide=true]:gap-6 data-[wide=true]:px-6',
        className
      )}
    >
      {/* Avatar: narrow 96 (xl) / wide 80 (lg)。view-transition-name 让 VT 把头像当连续元素：
          从旧帧（上方居中 96）morph 到新帧（左侧 80），位置 + 尺寸一并平滑过渡。 */}
      <div className="shrink-0 [view-transition-name:agent-detail-avatar]">
        <AgentAvatar
          name={name}
          src={detail.avatar}
          health={health}
          onEdit={onEditAvatar}
          size={isWide ? 'lg' : 'xl'}
        />
      </div>

      {/* right column: name + intro + (extra) + stats。view-transition-name 让 VT crossfade+morph 整列
          （narrow 居中堆叠 → wide 左对齐内联），内部 stats 重排被叠化盖住，不露瞬切。 */}
      <div
        className={cn(
          // narrow: 居中堆叠；wide: 左对齐撑满右侧
          // min-w-0：wide 下 flex-1 默认 min-width:auto 会被长名撑大溢出 section，须显式允许收缩
          'flex w-full min-w-0 flex-col items-center [view-transition-name:agent-detail-info-col]',
          'group-data-[wide=true]/info:flex-1 group-data-[wide=true]/info:items-start'
        )}
      >
        {/* name: 20/28/w400 单行截断（超出 hover tooltip）；hover 名称区右侧 8px(gap-2) 显示编辑 icon */}
        <div className="group/name mt-3 flex w-full min-w-0 items-center justify-center gap-2 group-data-[wide=true]/info:mt-0 group-data-[wide=true]/info:justify-start">
          <Text
            variant="plain"
            lineClamp={1}
            className="min-w-0 max-w-full shrink text-xl font-normal leading-7 text-n900"
          >
            {name}
          </Text>
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger
                render={
                  <button
                    type="button"
                    onClick={() => setEditOpen(true)}
                    aria-label={i18n.formatMessage(editTooltipMsg)}
                    // Figma 14008:78581：18px 编辑 icon + 容器 padding3(size-6) + radius6 + hover bg-n900/5。
                    // 默认 hidden（不占位 → 名称居中不被挤偏），hover 名称区(group/name)才 flex 显示
                    className="hidden size-6 shrink-0 items-center justify-center rounded-md hover:bg-n900/5 group-hover/name:flex"
                  >
                    <EditOutlined className="text-[18px]! text-n500" />
                  </button>
                }
              />
              <TooltipContent side="bottom">{i18n.formatMessage(editTooltipMsg)}</TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>

        {/* intro: narrow 12/16, wide 12/20；最多两行截断（超出 hover tooltip） */}
        <Text
          variant="plain"
          lineClamp={2}
          className={cn(
            'mt-2.5 w-full text-center text-xs leading-4 text-n500',
