import { type ReactElement } from 'react';

import { defineMessages, useI18n } from '@apaas-ai/i18n';
import { cn } from '@apaas-base/design/lib/utils';

import type { WorkbenchModule } from '@/apis/types';
import { CodeViewer, inferLanguage } from '@/components/code-editor';

const messages = defineMessages({
  emptyFile: { id: 'agent_profile.empty_file', defaultMessage: '文件为空' },
});

interface ProfileDocumentViewProps {
  meta: WorkbenchModule.Spi.Aggregator.PersonalizationDocumentMeta;
  document?: WorkbenchModule.Spi.Aggregator.GetPersonalizationDocumentResponse;
  value: string;
  onChange: (nextValue: string) => void;
}

export function ProfileDocumentView({
  meta,
  document,
  value,
  onChange,
}: ProfileDocumentViewProps): ReactElement {
  const i18n = useI18n();
  const fileName = document?.fileName ?? meta.fileName ?? meta.documentType;
  const description = document?.description ?? meta.description;
  const editable = document?.editable ?? meta.editable ?? false;

  return (
    <div className="flex min-h-0 flex-1 flex-col px-6 pt-5">
      <div className="text-sm font-medium leading-5 text-n900">{fileName}</div>
      {description ? <div className="mt-1 text-xs leading-4 text-n500">{description}</div> : null}
      <div className="mt-3 h-px bg-n200" />
      <div className="min-h-[360px] flex-1 py-6">
        <CodeViewer
          value={value}
          language={inferLanguage(fileName)}
          editable={editable}
          highlight={false}
          lineWrapping
          onChange={editable ? onChange : undefined}
          placeholder={i18n.formatMessage(messages.emptyFile)}
          className={cn(
            'h-full min-h-full text-n700',
            '[&_.cm-gutters]:hidden',
            '[&_.cm-content]:p-0',
            '[&_.cm-line]:px-0',
            '[&_.cm-editor]:min-h-full',
            '[&_.cm-editor]:bg-transparent',
            '[&_.cm-activeLine]:bg-transparent',
            '[&_.cm-focused]:outline-none'
          )}
        />
      </div>
    </div>
  );
}

