import { describe, expect, it, vi } from 'vitest';

import type { WorkbenchModule } from '@/apis/types';

import { ProfileDocumentView } from './profile-document-view';

const codeViewerMock = vi.hoisted(() => ({
  render: vi.fn(
    ({
      value,
      editable,
      onChange,
      language,
      placeholder,
    }: {
      value: string;
      editable?: boolean;
      onChange?: (value: string) => void;
      language?: string;
      placeholder?: string;
    }) => (
      <textarea
        data-testid="code-viewer"
        data-language={language}
        readOnly={!editable}
        placeholder={placeholder}
        value={value}
        onChange={(event) => onChange?.(event.target.value)}
      />
    )
  ),
}));

vi.mock('@/components/code-editor', () => ({
  CodeViewer: codeViewerMock.render,
  inferLanguage: (fileName: string) => (fileName.endsWith('.md') ? 'markdown' : 'javascript'),
}));

vi.mock('@apaas-ai/i18n', () => ({
  defineMessages: (messages: unknown) => messages,
  useI18n: () => ({
    formatMessage: (message: { defaultMessage?: string; id: string }) => message.defaultMessage ?? message.id,
  }),
}));

const editableMeta: WorkbenchModule.Spi.Aggregator.PersonalizationDocumentMeta = {
  documentType: 'soul',
  fileName: 'SOUL.md',
  title: '行为准则',
  description: '底线规则',
  editable: true,
};

const editableDocument: WorkbenchModule.Spi.Aggregator.GetPersonalizationDocumentResponse = {
  documentType: 'soul',
  fileName: 'SOUL.md',
  title: '行为准则',
  description: '底线规则',
  content: 'saved',
  editable: true,
  updatedAt: 1,
};

describe('ProfileDocumentView', () => {
  it('renders file metadata and wires editable CodeViewer changes', () => {
    const onChange = vi.fn();

    render(
      <ProfileDocumentView
        meta={editableMeta}
        document={editableDocument}
        value="draft"
        onChange={onChange}
      />
    );

    expect(screen.getByText('SOUL.md')).toBeTruthy();
    expect(screen.getByText('底线规则')).toBeTruthy();
    expect(screen.getByTestId('code-viewer').getAttribute('data-language')).toBe('markdown');

    fireEvent.change(screen.getByTestId('code-viewer'), { target: { value: 'next draft' } });

    expect(onChange).toHaveBeenCalledWith('next draft');
  });

  it('keeps readonly files non-editable and only shows the backend file description', () => {
    const onChange = vi.fn();
    const readonlyDocument = {
      ...editableDocument,
      editable: false,
      description: '当前文件不可编辑',
      readonlyReason: '不应单独展示',
    } as WorkbenchModule.Spi.Aggregator.GetPersonalizationDocumentResponse & { readonlyReason: string };

    render(
      <ProfileDocumentView
        meta={editableMeta}
        document={readonlyDocument}
        value="readonly"
        onChange={onChange}
      />
    );

    expect(screen.getByText('当前文件不可编辑')).toBeTruthy();
    expect(screen.queryByText('不应单独展示')).toBeNull();
    expect(screen.getByTestId('code-viewer')).toHaveProperty('readOnly', true);

    fireEvent.change(screen.getByTestId('code-viewer'), { target: { value: 'ignored' } });

    expect(onChange).not.toHaveBeenCalled();
  });
});

